examples:
spi {
  #address-cells = <1>;
  #size-cells = <0>;

  ad7292: adc@0 {
    compatible = "adi,ad7292";
    reg = <0>;
    spi-max-frequency = <25000000>;
    vref-supply = <&adc_vref>;
    spi-cpha;

    #address-cells = <1>;
    #size-cells = <0>;

    channel@0 {
      reg = <0>;
      diff-channels = <0 1>;
    };
    channel@2 {
      reg = <2>;
    };
    channel@3 {
      reg = <3>;
    };
    channel@4 {
      reg = <4>;
    };
    channel@5 {
      reg = <5>;
    };
    channel@6 {
      reg = <6>;
    };
    channel@7 {
      reg = <7>;
    };
  };
};
